<template>

    <!-- 歷史訂單區域，未來將使用v-for動態產生歷史訂單 -->
    <div class="container-fluid w-100 mt-3">
        <!-- 表格 -->
        <div class="table-responsive">
            <table class="table table-hover text-start ">
            <!-- 表頭 -->
            <thead>
                <tr class="d-none d-md-table-row">
                <th scope="col">訂單號碼</th>
                <th scope="col">訂單日期</th>
                <th scope="col">合計</th>
                <th scope="col">訂單狀態</th>
                <th scope="col">  </th>
                </tr>
            </thead>
            <!-- 表格本體 -->
            <tbody>
                <tr v-if="historyOrders.items.length===0">
                    <td colspan="5">
                        尚未有任何歷史訂單
                    </td>
                </tr>
                <tr  v-for="order in historyOrders.items" :key="order.orderId">
                <th scope="row">{{ order.orderId }}</th>
                <td>{{order.orderDate}}</td>
                <td>NT${{order.totalAmount}}</td>
                <td>待出貨</td>
                <td>
                <router-link :to="`/historyorderdetail?orderid=${order.orderId}`">
                    <button class="btn btn-secondary w-50">查閱</button>
                </router-link>
                </td>
                </tr>                
            </tbody>
            </table> 
        </div>         
    </div>
</template>

<script>
import {onMounted,reactive} from 'vue'
import axios from 'axios'
export default {
 name:'HistoryOrders',
 setup(){
    let historyOrders=reactive({'items':{}})
    let isLogin =localStorage.getItem('isLogin')
    onMounted(() => {
        axios.post('/historyorders',{'isLogin':isLogin},{ headers: { 'Content-Type': 'application/json' } }).then(
            response =>{
                historyOrders.items=response.data
                console.log(historyOrders)
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })

    return {
       historyOrders
    }
 }

}
</script>

